from skimage import io, img_as_float, img_as_ubytefrom matplotlib import pyplot as pltimport numpy as npfrom skimage.restoration import denoise_nl_means, estimate_sigma# https://www.youtube.com/watch?v=6P8YhJa2V6oimg = img_as_float(io.imread("/Users/grnho/Desktop/image-processing-fundamentals/data/Alloy_noisy.jpg"))plt.figure(figsize=(6,4))plt.hist(img.flat, bins=100, range=(0,1))plt.xlabel("Pixel Intensity")plt.ylabel("Frequency")plt.title("Image Histogram")plt.show()sigma_est = np.mean(estimate_sigma(img, channel_axis = None))denoise_img = denoise_nl_means(img, h=1.15 * sigma_est, fast_mode=True,                               patch_size=5, patch_distance=3, channel_axis = None)from skimage import exposureplt.figure(figsize=(6,4))plt.hist(denoise_img.flat, bins=100, range=(0., 1))plt.imshow(denoise_img, cmap='gray')eq_img = exposure.equalize_hist(denoise_img)eq_img = exposure.equalize_adapthist(denoise_img)plt.figure(figsize=(6,4))plt.hist(eq_img.flat, bins=100, range=(0., 1))plt.imshow(eq_img, cmap='gray')markers = np.zeros(img.shape, dtype = np.uint)markers[(eq_img <0.6)&(eq_img >=0.3)] =1markers[(eq_img >0.8)&(eq_img <0.99)] =2plt.imshow(markers)from skimage.segmentation import random_walkerlabels = random_walker(eq_img, markers, beta = 10, mode = 'bf')plt.imshow(labels)segm1 = (labels==1)segm2 = (labels ==2)all_segments = np.zeros((img.shape[0], img.shape[1], 3))all_segments[segm1] = (1, 0, 0)all_segments[segm2] = (0, 1, 0)plt.imshow(all_segments)